      sum(agricultural_area_grid_municipality_ha, na.rm = TRUE),
    native_vegetation_area_ha =
      sum(native_area_grid_municipality_ha, na.rm = TRUE),
    agricultural_area_near_native_500m_ha =
      sum(agricultural_area_near_native_500m_grid_municipality_ha, na.rm = TRUE),
    agricultural_area_near_native_1000m_ha =
      sum(agricultural_area_near_native_1000m_grid_municipality_ha, na.rm = TRUE),
    agricultural_area_near_native_2000m_ha =
      sum(agricultural_area_near_native_2000m_grid_municipality_ha, na.rm = TRUE),
    agricultural_area_near_native_3000m_ha =
      sum(agricultural_area_near_native_3000m_grid_municipality_ha, na.rm = TRUE),
    pd_grid_mean_2020_2024 =
