# ------------------------------------------------------------
# 33) Crop-level pollination demand
# ------------------------------------------------------------

crop_pd_year <- pam %>%
  filter(
    variable_name_clean == "quantidade produzida",
    is_main_pollination_crop
  ) %>%
  mutate(
    crop_production = value,
    crop_pd = crop_production * dependence_score
  ) %>%
  group_by(
    year,
    municipality_code,
    municipality_name,
    crop_code,
    crop_name,
    pollination_dependence
  ) %>%
  summarise(
    crop_production =
      sum(crop_production, na.rm = TRUE),
    crop_pd =
      sum(crop_pd, na.rm = TRUE),
    .groups = "drop"
  )

crop_pd_mean <- crop_pd_year %>%
  group_by(
    municipality_code,
    municipality_name,
    crop_code,
    crop_name,
    pollination_dependence
  ) %>%
  summarise(
    crop_production_mean_2020_2024 =
      mean(crop_production, na.rm = TRUE),
    crop_pd_mean_2020_2024 =
      mean(crop_pd, na.rm = TRUE),
    .groups = "drop"
  )

# ------------------------------------------------------------
# 34) Pollinator-dependent crop diversity by municipality
# Shannon index using crop PD proportions
# ------------------------------------------------------------

crop_diversity_municipality <- crop_pd_mean %>%
  group_by(municipality_code, municipality_name) %>%
  mutate(
    total_pd_municipality =
      sum(crop_pd_mean_2020_2024, na.rm = TRUE),
    p_crop = ifelse(
      total_pd_municipality > 0,
      crop_pd_mean_2020_2024 / total_pd_municipality,
      NA_real_
    )
  ) %>%
  summarise(
    shannon_pd_crops =
      -sum(p_crop * log(p_crop), na.rm = TRUE),
    n_main_pollination_crops =
      n_distinct(crop_code[crop_pd_mean_2020_2024 > 0]),
    total_pd_municipality =
      first(total_pd_municipality),
    .groups = "drop"
  )

# ------------------------------------------------------------
# 35) Dominant crop by municipality
# ------------------------------------------------------------

dominant_crop_municipality <- crop_pd_mean %>%
  group_by(municipality_code, municipality_name) %>%
  mutate(
    total_pd_municipality =
      sum(crop_pd_mean_2020_2024, na.rm = TRUE),
    crop_pd_percent = ifelse(
      total_pd_municipality > 0,
      crop_pd_mean_2020_2024 / total_pd_municipality * 100,
      NA_real_
    )
  ) %>%
  arrange(desc(crop_pd_mean_2020_2024), .by_group = TRUE) %>%
  slice(1) %>%
  ungroup() %>%
  transmute(
    municipality_code,
    municipality_name,
    dominant_crop_municipality = crop_name,
    dominant_crop_code_municipality = crop_code,
    dominant_crop_dependence_municipality = pollination_dependence,
    dominant_crop_pd_municipality = crop_pd_mean_2020_2024,
    dominant_crop_percent_municipality = crop_pd_percent,
    total_pd_municipality
  )

n_crops_municipality <- crop_pd_mean %>%
  filter(crop_pd_mean_2020_2024 > 0) %>%
  group_by(municipality_code, municipality_name) %>%
  summarise(
    n_main_pollination_crops = n_distinct(crop_code),
    .groups = "drop"
  )

dominant_crop_municipality <- dominant_crop_municipality %>%
  left_join(
    n_crops_municipality,
    by = c("municipality_code", "municipality_name")
  )

# ------------------------------------------------------------
# 36) Dominant municipality in each grid
# ------------------------------------------------------------

dominant_municipality_grid <- grid_municipality_allocated %>%
  group_by(grid_id, municipality_code) %>%
  summarise(
    municipality_grid_intersection_area_ha =
      sum(intersection_area_ha, na.rm = TRUE),
    .groups = "drop"
  ) %>%
  group_by(grid_id) %>%
  slice_max(
    municipality_grid_intersection_area_ha,
    n = 1,
    with_ties = FALSE
  ) %>%
  ungroup()

# ------------------------------------------------------------
# 37) Add municipal crop diversity and municipal dominant crop
# ------------------------------------------------------------

grid_mismatch <- grid_mismatch %>%
  select(
    -any_of(c(
      "dominant_municipality_code",
      "shannon_pd_crops",
      "n_main_pollination_crops",
      "dominant_crop_municipality",
      "dominant_crop_dependence_municipality",
      "dominant_crop_pd_municipality",
      "dominant_crop_percent_municipality"
    ))
  ) %>%
  left_join(
    dominant_municipality_grid %>%
      select(
        grid_id,
        dominant_municipality_code = municipality_code
      ),
    by = "grid_id"
  ) %>%
  left_join(
    crop_diversity_municipality %>%
      select(
        dominant_municipality_code = municipality_code,
        shannon_pd_crops,
        n_main_pollination_crops
      ),
    by = "dominant_municipality_code"
  ) %>%
  left_join(
    dominant_crop_municipality %>%
      select(
        dominant_municipality_code = municipality_code,
        dominant_crop_municipality,
        dominant_crop_dependence_municipality,
        dominant_crop_pd_municipality,
        dominant_crop_percent_municipality
      ),
    by = "dominant_municipality_code"
  )

# ------------------------------------------------------------
# 38) Allocate crop-level municipal PD to grid cells
# Same dasymetric allocation procedure based on agricultural area
# ------------------------------------------------------------

crop_grid_allocated <- grid_municipality_area %>%
  left_join(municipal_area, by = "municipality_code") %>%
  left_join(crop_pd_mean, by = "municipality_code") %>%
  mutate(
    agricultural_area_share_municipality = ifelse(
      agricultural_area_municipality_ha > 0,
      agricultural_area_grid_municipality_ha / agricultural_area_municipality_ha,
      0
    ),
    crop_pd_grid =
      crop_pd_mean_2020_2024 * agricultural_area_share_municipality,
    crop_pd_grid =
      tidyr::replace_na(crop_pd_grid, 0)
  )

# ------------------------------------------------------------
# 39) Dominant crop directly by grid
# Dominant crop = largest share of total grid-level PD
# ------------------------------------------------------------

dominant_crop_grid <- crop_grid_allocated %>%
  filter(!is.na(crop_code)) %>%
  group_by(
    grid_id,
    crop_code,
    crop_name,
    pollination_dependence
  ) %>%
  summarise(
    crop_pd_grid =
      sum(crop_pd_grid, na.rm = TRUE),
    .groups = "drop"
  ) %>%
  group_by(grid_id) %>%
  mutate(
    total_pd_grid_from_crops =
      sum(crop_pd_grid, na.rm = TRUE),
    crop_pd_percent_grid = ifelse(
      total_pd_grid_from_crops > 0,
      crop_pd_grid / total_pd_grid_from_crops * 100,
      NA_real_
    )
  ) %>%
  filter(total_pd_grid_from_crops > 0) %>%
  arrange(desc(crop_pd_grid), .by_group = TRUE) %>%
  slice(1) %>%
  ungroup() %>%
  transmute(
    grid_id = as.character(grid_id),
    dominant_crop_grid = crop_name,
    dominant_crop_code_grid = crop_code,
    dominant_crop_dependence_grid = pollination_dependence,
    dominant_crop_pd_grid = crop_pd_grid,
    dominant_crop_percent_grid = crop_pd_percent_grid,
    total_pd_grid_from_crops
  )

# ------------------------------------------------------------
# 40) Add grid-level dominant crop safely
# ------------------------------------------------------------

grid_mismatch <- grid_mismatch %>%
  select(
    -matches("^dominant_crop_grid"),
    -matches("^dominant_crop_code_grid"),
    -matches("^dominant_crop_dependence_grid"),
    -matches("^dominant_crop_pd_grid"),
    -matches("^dominant_crop_percent_grid"),
    -matches("^total_pd_grid_from_crops")
  ) %>%
  mutate(grid_id = as.character(grid_id)) %>%
  left_join(
    dominant_crop_grid,
    by = "grid_id"
  )

# ------------------------------------------------------------
# 41) Summary of dominant crops in critical hotspots
# ------------------------------------------------------------

dominant_crop_hotspots_summary <- grid_mismatch %>%
  sf::st_drop_geometry() %>%
  filter(mismatch_category == "high demand + low supply") %>%
  group_by(dominant_crop_grid) %>%
  summarise(
    n_grid_cells = n(),
    pd_total =
      sum(pd_grid_mean_2020_2024, na.rm = TRUE),
    ev_usd_total =
      sum(ev_usd_grid_mean_2020_2024, na.rm = TRUE),
    apev_usd_total =
      sum(apev_usd_grid_mean_2020_2024, na.rm = TRUE),
    mean_dominant_crop_percent =
      mean(dominant_crop_percent_grid, na.rm = TRUE),
    mean_risk_deficit =
      mean(risk_deficit, na.rm = TRUE),
    .groups = "drop"
  ) %>%
  arrange(desc(pd_total))


# ============================================================
# PART H — CORRELATION ANALYSIS
# ============================================================

# ------------------------------------------------------------
# 42) Spearman and Pearson correlations among grid-level metrics
# ------------------------------------------------------------

metrics_correlation <- grid_mismatch %>%
  sf::st_drop_geometry() %>%
  select(
