# ============================================================
# PART N — SENSITIVITY ANALYSIS: NO-SOYBEAN SCENARIO
# ============================================================
# Rationale:
# - Soybean is controversial in pollination-dependence assessments
#   because it is predominantly self-pollinating and its response to
#   insects can vary by cultivar, region and environmental context.
# - This sensitivity scenario removes soybean from PD and APEV
#   calculations and evaluates whether high-demand/low-supply
#   hotspots persist without soybean.
#
# Important:
# - The main robustness test uses the SAME demand and supply
#   thresholds from the main scenario. This avoids artificially creating
#   a new top 25% demand class after soybean removal.
# - A secondary "relative no-soy" classification is also produced,
#   using quantiles recalculated only within the no-soy scenario.
# ============================================================

# ------------------------------------------------------------
# N1) Output folders
# ------------------------------------------------------------

sensitivity_dir <- file.path(output_dir, "sensitivity_no_soy")
tab_sensitivity_dir <- file.path(tab_dir, "sensitivity_no_soy")

dir.create(sensitivity_dir, showWarnings = FALSE, recursive = TRUE)
dir.create(tab_sensitivity_dir, showWarnings = FALSE, recursive = TRUE)

# ------------------------------------------------------------
# N2) Helper functions
# ------------------------------------------------------------

normalize_crop_text <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  x %>%
    stringr::str_to_lower() %>%
    iconv(from = "UTF-8", to = "ASCII//TRANSLIT") %>%
    stringr::str_replace_all("[^[:alnum:]]+", " ") %>%
    stringr::str_squish()
}

rescale01_with_range <- function(x, reference_range) {
  if (
    length(reference_range) != 2 ||
    any(is.na(reference_range)) ||
    any(is.infinite(reference_range)) ||
    diff(reference_range) == 0
  ) {
    return(rep(0, length(x)))
  }
  
  out <- (x - reference_range[1]) /
    (reference_range[2] - reference_range[1])
  
  # Keeps the no-soy values on the original 0–1 scale.
  # Values below or above the original range are truncated.
  pmin(pmax(out, 0), 1)
}

percent_change <- function(new_value, old_value) {
  ifelse(
    is.na(old_value) | old_value == 0,
    NA_real_,
    (new_value - old_value) / old_value * 100
  )
}

# ------------------------------------------------------------
# N3) Identify soybean crop code(s)
# ------------------------------------------------------------
# This is intentionally text-based and robust to Portuguese/English names.
# It searches crop_name, crop_name_english and the PAM reference name.

soy_crop_lookup <- pam %>%
  dplyr::distinct(
    crop_code,
    crop_name,
    crop_name_english,
    pam_crop_name_reference
  ) %>%
  dplyr::mutate(
    crop_name_clean = normalize_crop_text(crop_name),
    crop_name_english_clean = normalize_crop_text(crop_name_english),
    pam_crop_name_reference_clean =
      normalize_crop_text(pam_crop_name_reference),
    is_soybean_name =
      stringr::str_detect(crop_name_clean, "\\bsoja\\b") |
      stringr::str_detect(crop_name_english_clean, "\\bsoy\\b|\\bsoybean\\b|\\bsoybeans\\b|\\bsoya\\b") |
      stringr::str_detect(pam_crop_name_reference_clean, "\\bsoja\\b|\\bsoy\\b|\\bsoybean\\b|\\bsoybeans\\b|\\bsoya\\b")
  ) %>%
  dplyr::filter(is_soybean_name) %>%
  dplyr::arrange(crop_code)

if (nrow(soy_crop_lookup) == 0) {
  stop(
    "No soybean crop was detected. Check crop names/codes in PAM and ",
    "pollination_dependence_reference.xlsx before running the no-soy scenario."
  )
}

soy_crop_codes <- unique(soy_crop_lookup$crop_code)

cat("\nSoybean crop code(s) removed in the sensitivity scenario:\n")
print(
  soy_crop_lookup %>%
    dplyr::select(
      crop_code,
      crop_name,
      crop_name_english,
      pam_crop_name_reference
    )
)

readr::write_csv(
  soy_crop_lookup,
  file.path(tab_sensitivity_dir, "soybean_crop_codes_removed.csv")
)

# ============================================================
# PART N-A — MUNICIPAL DEMAND WITHOUT SOYBEAN
# ============================================================

# ------------------------------------------------------------
# N4) Select production quantity excluding soybean
# ------------------------------------------------------------

pam_quantity_main_no_soy <- pam %>%
  dplyr::filter(
    variable_name_clean == "quantidade produzida",
    is_main_pollination_crop,
    !crop_code %in% soy_crop_codes
  )

# ------------------------------------------------------------
# N5) Annual municipal pollination demand without soybean
# PD_no_soy_imy = Q_imy * D_i, excluding soybean
# ------------------------------------------------------------

municipal_demand_year_no_soy <- pam_quantity_main_no_soy %>%
  dplyr::mutate(
    production_quantity_no_soy = value,
    pollination_demand_crop_no_soy =
      production_quantity_no_soy * dependence_score
  ) %>%
  dplyr::group_by(year, municipality_code, municipality_name) %>%
  dplyr::summarise(
    production_main_total_no_soy =
      sum(production_quantity_no_soy, na.rm = TRUE),
    pollination_demand_no_soy =
      sum(pollination_demand_crop_no_soy, na.rm = TRUE),
    n_main_pollination_crops_no_soy =
      dplyr::n_distinct(crop_code[production_quantity_no_soy > 0]),
    .groups = "drop"
  )

# ------------------------------------------------------------
# N6) Mean municipal demand without soybean, 2020–2024
# ------------------------------------------------------------

municipal_demand_mean_no_soy <- municipal_demand_year_no_soy %>%
  dplyr::group_by(municipality_code, municipality_name) %>%
  dplyr::summarise(
    production_main_total_no_soy_mean_2020_2024 =
      mean(production_main_total_no_soy, na.rm = TRUE),
    PD_no_soy_mean_2020_2024 =
      mean(pollination_demand_no_soy, na.rm = TRUE),
    n_main_crops_no_soy_mean_2020_2024 =
      mean(n_main_pollination_crops_no_soy, na.rm = TRUE),
    .groups = "drop"
  )

# ============================================================
# PART N-B — ECONOMIC VALUE WITHOUT SOYBEAN
# ============================================================

# ------------------------------------------------------------
# N7) Annual EV, APEV and RV without soybean
# ------------------------------------------------------------
# In this sensitivity scenario:
# - EV_no_soy excludes soybean from total agricultural production value.
# - APEV_no_soy excludes soybean from pollinator-attributable value.
# - RV_no_soy = APEV_no_soy / EV_no_soy * 100.
#
# An additional denominator using all-crop EV is also retained for audit:
# - RV_no_soy_using_all_crop_EV = APEV_no_soy / EV_all_crops * 100.

municipal_economic_year_brl_no_soy <- pam_value_all %>%
  dplyr::mutate(
    is_soybean_crop = crop_code %in% soy_crop_codes,
    value_brl_thousand = value,
    pollination_value_brl_thousand_no_soy = ifelse(
      is_main_pollination_crop & !is_soybean_crop,
      value_brl_thousand * dependence_score,
      0
    )
  ) %>%
  dplyr::group_by(year, municipality_code, municipality_name) %>%
  dplyr::summarise(
    EV_brl_thousand_all_crops =
      sum(value_brl_thousand, na.rm = TRUE),
    EV_brl_thousand_no_soy =
      sum(
        ifelse(!is_soybean_crop, value_brl_thousand, 0),
        na.rm = TRUE
      ),
    APEV_brl_thousand_no_soy =
      sum(pollination_value_brl_thousand_no_soy, na.rm = TRUE),
    n_crops_total_economic_no_soy =
      dplyr::n_distinct(
        crop_code[
          !is_soybean_crop &
            value_brl_thousand > 0
        ]
      ),
    n_main_pollination_crops_economic_no_soy =
      dplyr::n_distinct(
        crop_code[
          is_main_pollination_crop &
            !is_soybean_crop &
            value_brl_thousand > 0
        ]
      ),
    .groups = "drop"
  ) %>%
  dplyr::mutate(
    RV_percent_no_soy = ifelse(
      EV_brl_thousand_no_soy > 0,
      APEV_brl_thousand_no_soy / EV_brl_thousand_no_soy * 100,
      NA_real_
    ),
    RV_percent_no_soy_using_all_crop_EV = ifelse(
      EV_brl_thousand_all_crops > 0,
      APEV_brl_thousand_no_soy / EV_brl_thousand_all_crops * 100,
      NA_real_
    )
  )

# ------------------------------------------------------------
# N8) Convert EV and APEV to USD
# ------------------------------------------------------------

municipal_economic_year_no_soy <- municipal_economic_year_brl_no_soy %>%
  dplyr::left_join(exchange_rates, by = "year") %>%
  dplyr::mutate(
    EV_usd_all_crops =
      (EV_brl_thousand_all_crops * 1000) / brl_per_usd,
    EV_usd_no_soy =
      (EV_brl_thousand_no_soy * 1000) / brl_per_usd,
    APEV_usd_no_soy =
      (APEV_brl_thousand_no_soy * 1000) / brl_per_usd
  )

# ------------------------------------------------------------
# N9) Mean EV, APEV and RV without soybean, 2020–2024
# ------------------------------------------------------------

municipal_economic_mean_no_soy <- municipal_economic_year_no_soy %>%
  dplyr::group_by(municipality_code, municipality_name) %>%
  dplyr::summarise(
    EV_usd_all_crops_mean_2020_2024 =
      mean(EV_usd_all_crops, na.rm = TRUE),
    EV_usd_no_soy_mean_2020_2024 =
      mean(EV_usd_no_soy, na.rm = TRUE),
    APEV_usd_no_soy_mean_2020_2024 =
      mean(APEV_usd_no_soy, na.rm = TRUE),
    RV_percent_no_soy_mean_2020_2024 =
      mean(RV_percent_no_soy, na.rm = TRUE),
    RV_percent_no_soy_using_all_crop_EV_mean_2020_2024 =
      mean(RV_percent_no_soy_using_all_crop_EV, na.rm = TRUE),
    EV_brl_thousand_no_soy_mean_2020_2024 =
      mean(EV_brl_thousand_no_soy, na.rm = TRUE),
    APEV_brl_thousand_no_soy_mean_2020_2024 =
      mean(APEV_brl_thousand_no_soy, na.rm = TRUE),
    n_crops_total_economic_no_soy_mean_2020_2024 =
      mean(n_crops_total_economic_no_soy, na.rm = TRUE),
    n_main_pollination_crops_economic_no_soy_mean_2020_2024 =
      mean(n_main_pollination_crops_economic_no_soy, na.rm = TRUE),
    .groups = "drop"
  )

# Annual totals for no-soy economic sensitivity.
econ_year_total_no_soy <- municipal_economic_year_no_soy %>%
  dplyr::group_by(year) %>%
  dplyr::summarise(
    EV_usd_total_no_soy =
      sum(EV_usd_no_soy, na.rm = TRUE),
    APEV_usd_total_no_soy =
      sum(APEV_usd_no_soy, na.rm = TRUE),
    RV_percent_total_no_soy = ifelse(
      EV_usd_total_no_soy > 0,
      APEV_usd_total_no_soy / EV_usd_total_no_soy * 100,
      NA_real_
    ),
    EV_usd_total_all_crops =
      sum(EV_usd_all_crops, na.rm = TRUE),
    RV_percent_total_no_soy_using_all_crop_EV = ifelse(
      EV_usd_total_all_crops > 0,
      APEV_usd_total_no_soy / EV_usd_total_all_crops * 100,
      NA_real_
    ),
    .groups = "drop"
  )

# ============================================================
# PART N-C — DASyMETRIC REDISTRIBUTION WITHOUT SOYBEAN
# ============================================================

# ------------------------------------------------------------
# N10) Redistribute mean PD, EV and APEV to grid × municipality
# ------------------------------------------------------------

grid_municipality_allocated_no_soy <- grid_municipality_area %>%
  dplyr::left_join(municipal_area, by = "municipality_code") %>%
  dplyr::left_join(
    municipal_demand_mean_no_soy %>%
      dplyr::select(
        municipality_code,
        production_main_total_no_soy_mean_2020_2024,
        PD_no_soy_mean_2020_2024,
        n_main_crops_no_soy_mean_2020_2024
      ),
    by = "municipality_code"
  ) %>%
  dplyr::left_join(
    municipal_economic_mean_no_soy %>%
      dplyr::select(
        municipality_code,
        EV_usd_all_crops_mean_2020_2024,
        EV_usd_no_soy_mean_2020_2024,
        APEV_usd_no_soy_mean_2020_2024,
        RV_percent_no_soy_mean_2020_2024,
        RV_percent_no_soy_using_all_crop_EV_mean_2020_2024
      ),
    by = "municipality_code"
  ) %>%
  dplyr::mutate(
    agricultural_area_share_municipality = ifelse(
      agricultural_area_municipality_ha > 0,
      agricultural_area_grid_municipality_ha /
        agricultural_area_municipality_ha,
      0
    ),
    PD_no_soy_gym_mean_2020_2024 =
      PD_no_soy_mean_2020_2024 *
      agricultural_area_share_municipality,
    production_main_no_soy_gym_mean_2020_2024 =
      production_main_total_no_soy_mean_2020_2024 *
      agricultural_area_share_municipality,
    EV_usd_all_crops_gym_mean_2020_2024 =
      EV_usd_all_crops_mean_2020_2024 *
      agricultural_area_share_municipality,
    EV_usd_no_soy_gym_mean_2020_2024 =
      EV_usd_no_soy_mean_2020_2024 *
      agricultural_area_share_municipality,
    APEV_usd_no_soy_gym_mean_2020_2024 =
      APEV_usd_no_soy_mean_2020_2024 *
      agricultural_area_share_municipality
  ) %>%
  dplyr::mutate(
    dplyr::across(
      c(
        PD_no_soy_gym_mean_2020_2024,
        production_main_no_soy_gym_mean_2020_2024,
        EV_usd_all_crops_gym_mean_2020_2024,
        EV_usd_no_soy_gym_mean_2020_2024,
        APEV_usd_no_soy_gym_mean_2020_2024
      ),
      ~ tidyr::replace_na(.x, 0)
    )
  )

# ------------------------------------------------------------
# N11) Check whether municipal no-soy demand was preserved
# ------------------------------------------------------------

redistribution_check_no_soy <- grid_municipality_allocated_no_soy %>%
  dplyr::group_by(municipality_code) %>%
  dplyr::summarise(
    PD_no_soy_municipal_original =
      dplyr::first(tidyr::replace_na(PD_no_soy_mean_2020_2024, 0)),
    PD_no_soy_redistributed =
      sum(PD_no_soy_gym_mean_2020_2024, na.rm = TRUE),
    agricultural_area_municipality_ha =
      dplyr::first(agricultural_area_municipality_ha),
    difference =
      PD_no_soy_municipal_original - PD_no_soy_redistributed,
    .groups = "drop"
  )

redistribution_summary_no_soy <- redistribution_check_no_soy %>%
  dplyr::summarise(
    PD_no_soy_original_total =
      sum(PD_no_soy_municipal_original, na.rm = TRUE),
    PD_no_soy_redistributed_total =
      sum(PD_no_soy_redistributed, na.rm = TRUE),
    difference_total =
      PD_no_soy_original_total - PD_no_soy_redistributed_total,
    percent_lost = ifelse(
      PD_no_soy_original_total > 0,
      difference_total / PD_no_soy_original_total * 100,
      NA_real_
    )
  )

# ============================================================
# PART N-D — GRID-LEVEL DEMAND, VALUE AND MISMATCH WITHOUT SOY
# ============================================================

# ------------------------------------------------------------
# N12) Aggregate allocated no-soy values by grid
# ------------------------------------------------------------

grid_attributes_no_soy <- grid_municipality_allocated_no_soy %>%
  dplyr::group_by(grid_id) %>%
  dplyr::summarise(
    intersection_area_total_ha =
      sum(intersection_area_ha, na.rm = TRUE),
    agricultural_area_ha =
      sum(agricultural_area_grid_municipality_ha, na.rm = TRUE),
    native_vegetation_area_ha =
      sum(native_area_grid_municipality_ha, na.rm = TRUE),
    PD_grid_no_soy_mean_2020_2024 =
      sum(PD_no_soy_gym_mean_2020_2024, na.rm = TRUE),
    production_main_grid_no_soy_mean_2020_2024 =
      sum(production_main_no_soy_gym_mean_2020_2024, na.rm = TRUE),
    EV_usd_grid_all_crops_mean_2020_2024 =
      sum(EV_usd_all_crops_gym_mean_2020_2024, na.rm = TRUE),
    EV_usd_grid_no_soy_mean_2020_2024 =
      sum(EV_usd_no_soy_gym_mean_2020_2024, na.rm = TRUE),
    APEV_usd_grid_no_soy_mean_2020_2024 =
      sum(APEV_usd_no_soy_gym_mean_2020_2024, na.rm = TRUE),
    n_municipal_intersections =
      dplyr::n_distinct(municipality_code),
    .groups = "drop"
  ) %>%
  dplyr::mutate(
    RV_percent_grid_no_soy_mean_2020_2024 = ifelse(
      EV_usd_grid_no_soy_mean_2020_2024 > 0,
      APEV_usd_grid_no_soy_mean_2020_2024 /
        EV_usd_grid_no_soy_mean_2020_2024 * 100,
      NA_real_
    ),
    RV_percent_grid_no_soy_using_all_crop_EV_mean_2020_2024 = ifelse(
      EV_usd_grid_all_crops_mean_2020_2024 > 0,
      APEV_usd_grid_no_soy_mean_2020_2024 /
        EV_usd_grid_all_crops_mean_2020_2024 * 100,
      NA_real_
    )
  )

# ------------------------------------------------------------
# N13) Join no-soy attributes to grid geometry
# ------------------------------------------------------------

grid_final_no_soy <- grid %>%
  dplyr::left_join(grid_attributes_no_soy, by = "grid_id") %>%
  dplyr::mutate(
    grid_area_ha = as.numeric(sf::st_area(.)) / 10000,
    agricultural_area_ha =
      tidyr::replace_na(agricultural_area_ha, 0),
    native_vegetation_area_ha =
      tidyr::replace_na(native_vegetation_area_ha, 0),
    PD_grid_no_soy_mean_2020_2024 =
      tidyr::replace_na(PD_grid_no_soy_mean_2020_2024, 0),
    production_main_grid_no_soy_mean_2020_2024 =
      tidyr::replace_na(
        production_main_grid_no_soy_mean_2020_2024,
        0
      ),
    EV_usd_grid_all_crops_mean_2020_2024 =
      tidyr::replace_na(EV_usd_grid_all_crops_mean_2020_2024, 0),
    EV_usd_grid_no_soy_mean_2020_2024 =
      tidyr::replace_na(EV_usd_grid_no_soy_mean_2020_2024, 0),
    APEV_usd_grid_no_soy_mean_2020_2024 =
      tidyr::replace_na(APEV_usd_grid_no_soy_mean_2020_2024, 0),
    agricultural_proportion =
      agricultural_area_ha / grid_area_ha,
    native_vegetation_proportion =
      native_vegetation_area_ha / grid_area_ha,
    PD_density_grid_no_soy =
      PD_grid_no_soy_mean_2020_2024 / grid_area_ha,
    PD_density_agriculture_no_soy = ifelse(
      agricultural_area_ha > 0,
      PD_grid_no_soy_mean_2020_2024 / agricultural_area_ha,
      0
    ),
    has_agriculture = agricultural_area_ha > 1,
    has_pollination_demand_no_soy =
      PD_grid_no_soy_mean_2020_2024 > 0
  )

grid_agri_no_soy <- grid_final_no_soy %>%
  dplyr::filter(has_agriculture)

# ------------------------------------------------------------
# N14) Main-scenario reference ranges and thresholds
# ------------------------------------------------------------
# These preserve comparability with the original scenario.

demand_log_range_main <- range(
  log1p(grid_agri$pd_grid_mean_2020_2024),
  na.rm = TRUE
)

supply_range_main <- range(
  grid_agri$native_vegetation_proportion,
  na.rm = TRUE
)

# ------------------------------------------------------------
# N15) Calculate no-soy potential supply and mismatch
# ------------------------------------------------------------

grid_mismatch_no_soy <- grid_agri_no_soy %>%
  dplyr::mutate(
    habitat_agriculture_total_ha =
      agricultural_area_ha + native_vegetation_area_ha,
    native_supply_proportion =
      native_vegetation_proportion,
    habitat_agriculture_supply = ifelse(
      habitat_agriculture_total_ha > 0,
      native_vegetation_area_ha / habitat_agriculture_total_ha,
      NA_real_
    ),
    native_area_supply_log =
      log1p(native_vegetation_area_ha),
    
    # Main-scale standardization:
    # no-soy demand is evaluated using the original demand scale.
    demand_std_no_soy_main_scale =
      rescale01_with_range(
        log1p(PD_grid_no_soy_mean_2020_2024),
        demand_log_range_main
      ),
    supply_std_no_soy_main_scale =
      rescale01_with_range(
        native_supply_proportion,
        supply_range_main
      ),
    
    # Relative no-soy standardization:
    # this recalculates demand/supply quantiles inside the no-soy scenario.
    demand_std_no_soy_relative =
      rescale01(log1p(PD_grid_no_soy_mean_2020_2024)),
    supply_std_no_soy_relative =
      rescale01(native_supply_proportion),
    
    habitat_agriculture_supply_std_no_soy =
      rescale01(habitat_agriculture_supply),
    supply_std_area_no_soy =
      rescale01(native_area_supply_log),
    
    risk_deficit_no_soy_main_scale =
      demand_std_no_soy_main_scale *
      (1 - supply_std_no_soy_main_scale),
    mismatch_no_soy_main_scale =
      demand_std_no_soy_main_scale -
      supply_std_no_soy_main_scale,
    
    risk_deficit_no_soy_relative =
      demand_std_no_soy_relative *
      (1 - supply_std_no_soy_relative),
    mismatch_no_soy_relative =
      demand_std_no_soy_relative -
      supply_std_no_soy_relative,
    
    risk_deficit_habitat_agriculture_no_soy =
      demand_std_no_soy_relative *
      (1 - habitat_agriculture_supply_std_no_soy),
    risk_deficit_area_no_soy =
      demand_std_no_soy_relative *
      (1 - supply_std_area_no_soy)
  )

# ------------------------------------------------------------
# N16) No-soy relative thresholds
# ------------------------------------------------------------

risk_breaks_no_soy_relative <- quantile(
  grid_mismatch_no_soy$risk_deficit_no_soy_relative,
  probs = c(0, 0.25, 0.5, 0.75, 1),
  na.rm = TRUE
)

q_high_demand_no_soy_relative <- quantile(
  grid_mismatch_no_soy$demand_std_no_soy_relative,
  0.75,
  na.rm = TRUE
)

q_low_supply_no_soy_relative <- quantile(
  grid_mismatch_no_soy$supply_std_no_soy_relative,
  0.25,
  na.rm = TRUE
)

q_high_supply_no_soy_relative <- quantile(
  grid_mismatch_no_soy$supply_std_no_soy_relative,
  0.75,
  na.rm = TRUE
)

# ------------------------------------------------------------
# N17) Risk classes and mismatch categories without soybean
# ------------------------------------------------------------

grid_mismatch_no_soy <- grid_mismatch_no_soy %>%
  dplyr::mutate(
    # Comparable classification using original risk breaks.
    risk_class_no_soy_main_thresholds = dplyr::case_when(
      risk_deficit_no_soy_main_scale <= risk_breaks[2] ~ "low",
      risk_deficit_no_soy_main_scale <= risk_breaks[3] ~ "moderate",
      risk_deficit_no_soy_main_scale <= risk_breaks[4] ~ "high",
      TRUE ~ "very high"
    ),
    risk_class_no_soy_main_thresholds = factor(
      risk_class_no_soy_main_thresholds,
      levels = c("low", "moderate", "high", "very high")
    ),
    
    # Internal no-soy classification using no-soy risk breaks.
    risk_class_no_soy_relative_thresholds = dplyr::case_when(
      risk_deficit_no_soy_relative <= risk_breaks_no_soy_relative[2] ~ "low",
      risk_deficit_no_soy_relative <= risk_breaks_no_soy_relative[3] ~ "moderate",
      risk_deficit_no_soy_relative <= risk_breaks_no_soy_relative[4] ~ "high",
      TRUE ~ "very high"
    ),
    risk_class_no_soy_relative_thresholds = factor(
      risk_class_no_soy_relative_thresholds,
      levels = c("low", "moderate", "high", "very high")
    ),
    
    # Most important sensitivity classification:
    # high demand and low supply are judged against the main scenario.
    mismatch_category_no_soy_main_thresholds = dplyr::case_when(
      demand_std_no_soy_main_scale >= q_high_demand &
        supply_std_no_soy_main_scale <= q_low_supply ~
        "high demand + low supply",
      demand_std_no_soy_main_scale >= q_high_demand &
        supply_std_no_soy_main_scale > q_low_supply ~
        "high demand + moderate/high supply",
      demand_std_no_soy_main_scale < q_high_demand &
        supply_std_no_soy_main_scale <= q_low_supply ~
        "low/moderate demand + low supply",
      demand_std_no_soy_main_scale < q_high_demand &
        supply_std_no_soy_main_scale >= q_high_supply ~
        "low/moderate demand + high supply",
      TRUE ~ "intermediate condition"
    ),
    mismatch_category_no_soy_main_thresholds = factor(
      mismatch_category_no_soy_main_thresholds,
      levels = c(
        "high demand + low supply",
        "high demand + moderate/high supply",
        "low/moderate demand + low supply",
        "low/moderate demand + high supply",
        "intermediate condition"
      )
    ),
    
    # Secondary no-soy classification:
    # new high-demand cells are identified relative to the no-soy distribution.
    mismatch_category_no_soy_relative_thresholds = dplyr::case_when(
      demand_std_no_soy_relative >= q_high_demand_no_soy_relative &
        supply_std_no_soy_relative <= q_low_supply_no_soy_relative ~
        "high demand + low supply",
      demand_std_no_soy_relative >= q_high_demand_no_soy_relative &
        supply_std_no_soy_relative > q_low_supply_no_soy_relative ~
        "high demand + moderate/high supply",
      demand_std_no_soy_relative < q_high_demand_no_soy_relative &
        supply_std_no_soy_relative <= q_low_supply_no_soy_relative ~
        "low/moderate demand + low supply",
      demand_std_no_soy_relative < q_high_demand_no_soy_relative &
        supply_std_no_soy_relative >= q_high_supply_no_soy_relative ~
        "low/moderate demand + high supply",
      TRUE ~ "intermediate condition"
    ),
    mismatch_category_no_soy_relative_thresholds = factor(
      mismatch_category_no_soy_relative_thresholds,
      levels = c(
        "high demand + low supply",
        "high demand + moderate/high supply",
        "low/moderate demand + low supply",
        "low/moderate demand + high supply",
        "intermediate condition"
      )
    )
  ) %>%
  dplyr::left_join(grid_state, by = "grid_id")

# ============================================================
# PART N-E — CROP-LEVEL ANALYSIS WITHOUT SOYBEAN
# ============================================================

# ------------------------------------------------------------
# N18) Crop-level PD without soybean
# ------------------------------------------------------------

crop_pd_year_no_soy <- pam_quantity_main_no_soy %>%
  dplyr::mutate(
    crop_production_no_soy = value,
    crop_PD_no_soy = crop_production_no_soy * dependence_score
  ) %>%
  dplyr::group_by(
    year,
    municipality_code,
    municipality_name,
    crop_code,
    crop_name,
    pollination_dependence
  ) %>%
  dplyr::summarise(
    crop_production_no_soy =
      sum(crop_production_no_soy, na.rm = TRUE),
    crop_PD_no_soy =
      sum(crop_PD_no_soy, na.rm = TRUE),
    .groups = "drop"
  )

crop_pd_mean_no_soy <- crop_pd_year_no_soy %>%
  dplyr::group_by(
    municipality_code,
    municipality_name,
    crop_code,
    crop_name,
    pollination_dependence
  ) %>%
  dplyr::summarise(
    crop_production_no_soy_mean_2020_2024 =
      mean(crop_production_no_soy, na.rm = TRUE),
    crop_PD_no_soy_mean_2020_2024 =
      mean(crop_PD_no_soy, na.rm = TRUE),
    .groups = "drop"
  )

# ------------------------------------------------------------
# N19) Allocate no-soy crop-level municipal PD to grid cells
# ------------------------------------------------------------

crop_grid_allocated_no_soy <- grid_municipality_area %>%
  dplyr::left_join(municipal_area, by = "municipality_code") %>%
  dplyr::left_join(crop_pd_mean_no_soy, by = "municipality_code") %>%
  dplyr::mutate(
    agricultural_area_share_municipality = ifelse(
      agricultural_area_municipality_ha > 0,
      agricultural_area_grid_municipality_ha /
        agricultural_area_municipality_ha,
      0
    ),
    crop_PD_grid_no_soy =
      crop_PD_no_soy_mean_2020_2024 *
      agricultural_area_share_municipality,
    crop_PD_grid_no_soy =
      tidyr::replace_na(crop_PD_grid_no_soy, 0)
  )

# ------------------------------------------------------------
# N20) Dominant crop directly by grid without soybean
# ------------------------------------------------------------

dominant_crop_grid_no_soy <- crop_grid_allocated_no_soy %>%
  dplyr::filter(!is.na(crop_code)) %>%
  dplyr::group_by(
    grid_id,
    crop_code,
    crop_name,
    pollination_dependence
  ) %>%
  dplyr::summarise(
    crop_PD_grid_no_soy =
      sum(crop_PD_grid_no_soy, na.rm = TRUE),
    .groups = "drop"
  ) %>%
  dplyr::group_by(grid_id) %>%
  dplyr::mutate(
    total_PD_grid_from_crops_no_soy =
      sum(crop_PD_grid_no_soy, na.rm = TRUE),
    crop_PD_percent_grid_no_soy = ifelse(
      total_PD_grid_from_crops_no_soy > 0,
      crop_PD_grid_no_soy /
        total_PD_grid_from_crops_no_soy * 100,
      NA_real_
    )
  ) %>%
  dplyr::filter(total_PD_grid_from_crops_no_soy > 0) %>%
  dplyr::arrange(desc(crop_PD_grid_no_soy), .by_group = TRUE) %>%
  dplyr::slice(1) %>%
  dplyr::ungroup() %>%
  dplyr::transmute(
    grid_id = as.character(grid_id),
    dominant_crop_grid_no_soy = crop_name,
    dominant_crop_code_grid_no_soy = crop_code,
    dominant_crop_dependence_grid_no_soy = pollination_dependence,
    dominant_crop_PD_grid_no_soy = crop_PD_grid_no_soy,
    dominant_crop_percent_grid_no_soy = crop_PD_percent_grid_no_soy,
    total_PD_grid_from_crops_no_soy
  )

grid_mismatch_no_soy <- grid_mismatch_no_soy %>%
  dplyr::mutate(grid_id = as.character(grid_id)) %>%
  dplyr::left_join(
    dominant_crop_grid_no_soy,
    by = "grid_id"
  )

# ============================================================
# PART N-F — SUMMARIES AND HOTSPOTS WITHOUT SOYBEAN
# ============================================================

# ------------------------------------------------------------
# N21) General no-soy summary
# ------------------------------------------------------------

summary_general_no_soy <- grid_mismatch_no_soy %>%
  sf::st_drop_geometry() %>%
  dplyr::summarise(
    n_grid_cells_with_agriculture = dplyr::n(),
    agricultural_area_ha =
      sum(agricultural_area_ha, na.rm = TRUE),
    native_vegetation_area_ha =
      sum(native_vegetation_area_ha, na.rm = TRUE),
    PD_total_no_soy_mean_2020_2024 =
      sum(PD_grid_no_soy_mean_2020_2024, na.rm = TRUE),
    EV_usd_total_no_soy_mean_2020_2024 =
      sum(EV_usd_grid_no_soy_mean_2020_2024, na.rm = TRUE),
    EV_usd_total_all_crops_mean_2020_2024 =
      sum(EV_usd_grid_all_crops_mean_2020_2024, na.rm = TRUE),
    APEV_usd_total_no_soy_mean_2020_2024 =
      sum(APEV_usd_grid_no_soy_mean_2020_2024, na.rm = TRUE),
    RV_percent_total_no_soy = ifelse(
      EV_usd_total_no_soy_mean_2020_2024 > 0,
      APEV_usd_total_no_soy_mean_2020_2024 /
        EV_usd_total_no_soy_mean_2020_2024 * 100,
      NA_real_
    ),
    RV_percent_total_no_soy_using_all_crop_EV = ifelse(
      EV_usd_total_all_crops_mean_2020_2024 > 0,
      APEV_usd_total_no_soy_mean_2020_2024 /
        EV_usd_total_all_crops_mean_2020_2024 * 100,
      NA_real_
