hotspot_overlap_summary_no_soy <- tibble::tibble(
  comparison = c(
    "main hotspots vs no-soy hotspots using main thresholds",
    "main hotspots vs no-soy hotspots using relative no-soy thresholds"
  ),
  n_hotspots_main = length(main_hotspot_ids),
  n_hotspots_no_soy = c(
    length(no_soy_hotspot_ids_main_thresholds),
    length(no_soy_hotspot_ids_relative_thresholds)
  ),
  n_shared_hotspots = c(
    length(intersect(
      main_hotspot_ids,
      no_soy_hotspot_ids_main_thresholds
    )),
    length(intersect(
      main_hotspot_ids,
      no_soy_hotspot_ids_relative_thresholds
    ))
  )
) %>%
  dplyr::mutate(
    percent_main_hotspots_retained = ifelse(
      n_hotspots_main > 0,
      n_shared_hotspots / n_hotspots_main * 100,
      NA_real_
    ),
    percent_no_soy_hotspots_already_in_main = ifelse(
      n_hotspots_no_soy > 0,
      n_shared_hotspots / n_hotspots_no_soy * 100,
      NA_real_
    )
  )

# Cell-level comparison table.
main_cell_status <- grid_mismatch %>%
  sf::st_drop_geometry() %>%
  dplyr::transmute(
    grid_id = as.character(grid_id),
    main_mismatch_category = as.character(mismatch_category),
    main_risk_deficit = risk_deficit,
    main_PD = pd_grid_mean_2020_2024,
    main_APEV_usd = apev_usd_grid_mean_2020_2024,
    main_EV_usd = ev_usd_grid_mean_2020_2024,
    main_dominant_crop = dominant_crop_grid
  )

no_soy_cell_status <- grid_mismatch_no_soy %>%
  sf::st_drop_geometry() %>%
  dplyr::transmute(
    grid_id = as.character(grid_id),
    no_soy_mismatch_category_main_thresholds =
      as.character(mismatch_category_no_soy_main_thresholds),
    no_soy_mismatch_category_relative_thresholds =
      as.character(mismatch_category_no_soy_relative_thresholds),
    no_soy_risk_deficit_main_scale =
      risk_deficit_no_soy_main_scale,
    no_soy_risk_deficit_relative =
      risk_deficit_no_soy_relative,
    no_soy_PD = PD_grid_no_soy_mean_2020_2024,
    no_soy_APEV_usd = APEV_usd_grid_no_soy_mean_2020_2024,
    no_soy_EV_usd = EV_usd_grid_no_soy_mean_2020_2024,
    no_soy_dominant_crop = dominant_crop_grid_no_soy
  )

hotspot_overlap_cells_no_soy <- main_cell_status %>%
  dplyr::full_join(no_soy_cell_status, by = "grid_id") %>%
  dplyr::mutate(
    is_hotspot_main =
      main_mismatch_category == "high demand + low supply",
    is_hotspot_no_soy_main_thresholds =
      no_soy_mismatch_category_main_thresholds ==
      "high demand + low supply",
    is_hotspot_no_soy_relative_thresholds =
      no_soy_mismatch_category_relative_thresholds ==
      "high demand + low supply",
    hotspot_status_main_vs_no_soy_main_thresholds =
      dplyr::case_when(
        is_hotspot_main & is_hotspot_no_soy_main_thresholds ~
          "hotspot in both",
        is_hotspot_main & !is_hotspot_no_soy_main_thresholds ~
          "hotspot only in main",
        !is_hotspot_main & is_hotspot_no_soy_main_thresholds ~
          "hotspot only in no-soy",
        TRUE ~ "not hotspot in either"
      ),
    PD_change_no_soy_minus_main =
      no_soy_PD - main_PD,
    PD_percent_change_no_soy =
      percent_change(no_soy_PD, main_PD),
    APEV_change_no_soy_minus_main =
      no_soy_APEV_usd - main_APEV_usd,
    APEV_percent_change_no_soy =
      percent_change(no_soy_APEV_usd, main_APEV_usd)
  )

# ------------------------------------------------------------
# N30) Concentration by no-soy risk ranking
# ------------------------------------------------------------

risk_ranked_cells_no_soy <- grid_mismatch_no_soy %>%
  sf::st_drop_geometry() %>%
  dplyr::ungroup() %>%
  dplyr::filter(!is.na(risk_deficit_no_soy_main_scale)) %>%
  dplyr::arrange(dplyr::desc(risk_deficit_no_soy_main_scale)) %>%
  dplyr::mutate(
    risk_rank_no_soy = dplyr::row_number(),
    top_fraction_cells_no_soy = risk_rank_no_soy / dplyr::n(),
    top_percent_cells_no_soy = top_fraction_cells_no_soy * 100,
    
    PD_grid_no_soy_clean =
      tidyr::replace_na(PD_grid_no_soy_mean_2020_2024, 0),
    
    APEV_usd_grid_no_soy_clean =
      tidyr::replace_na(APEV_usd_grid_no_soy_mean_2020_2024, 0),
    
    EV_usd_grid_no_soy_clean =
      tidyr::replace_na(EV_usd_grid_no_soy_mean_2020_2024, 0),
    
    cumulative_PD_no_soy =
      cumsum(PD_grid_no_soy_clean),
    
    cumulative_APEV_usd_no_soy =
      cumsum(APEV_usd_grid_no_soy_clean),
    
    cumulative_EV_usd_no_soy =
      cumsum(EV_usd_grid_no_soy_clean),
    
    total_PD_no_soy =
      sum(PD_grid_no_soy_clean, na.rm = TRUE),
    
    total_APEV_no_soy =
      sum(APEV_usd_grid_no_soy_clean, na.rm = TRUE),
    
    total_EV_no_soy =
      sum(EV_usd_grid_no_soy_clean, na.rm = TRUE),
    
    cumulative_PD_no_soy_percent =
      dplyr::if_else(
        total_PD_no_soy > 0,
        cumulative_PD_no_soy / total_PD_no_soy * 100,
        NA_real_
      ),
    
    cumulative_APEV_no_soy_percent =
      dplyr::if_else(
        total_APEV_no_soy > 0,
        cumulative_APEV_usd_no_soy / total_APEV_no_soy * 100,
        NA_real_
      ),
    
    cumulative_EV_no_soy_percent =
      dplyr::if_else(
        total_EV_no_soy > 0,
        cumulative_EV_usd_no_soy / total_EV_no_soy * 100,
        NA_real_
      )
  )

# ------------------------------------------------------------
# N30b) Extract cumulative concentration at top-risk cells
# ------------------------------------------------------------

get_cumulative_at_top <- function(df, top_pct, col_name) {
  tmp <- df %>%
    dplyr::filter(top_percent_cells_no_soy <= top_pct)
  
  if (nrow(tmp) == 0) {
    return(NA_real_)
  }
  
  tmp[[col_name]][nrow(tmp)]
}

concentration_thresholds_no_soy <- tibble::tibble(
  top_percent_cells = c(1, 5, 10, 25),
  
  PD_no_soy_percent = sapply(
    top_percent_cells,
    \(p) get_cumulative_at_top(
      risk_ranked_cells_no_soy,
      p,
      "cumulative_PD_no_soy_percent"
    )
  ),
  
  APEV_no_soy_percent = sapply(
    top_percent_cells,
    \(p) get_cumulative_at_top(
      risk_ranked_cells_no_soy,
      p,
      "cumulative_APEV_no_soy_percent"
    )
  ),
  
  EV_no_soy_percent = sapply(
    top_percent_cells,
    \(p) get_cumulative_at_top(
      risk_ranked_cells_no_soy,
      p,
      "cumulative_EV_no_soy_percent"
    )
  )
)

print(concentration_thresholds_no_soy)

